import os
import json
import argparse
import heapq
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()

    last_target_coord = None

    for step in range(max_steps):
        try:
            neighbors = obs['neighbors']
            nodes = obs['nodes']
            explored_rate = obs.get('explored_rate', 0.0)
        except Exception:
            break
        if not neighbors or not nodes:
            break
        robot = np.array(obs['robot_pos'], dtype=float)

        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            break
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        late_phase = explored_rate >= 0.7

        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            if late_phase:
                score = np.sqrt(u) / (d + 1.0)
            else:
                score = u / (d + 1.0)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        chosen = None
        target_idx = -1
        if scored:
            target_idx = scored[0][1]
            if last_target_coord is not None:
                for sc, idx, u, d in scored[:5]:
                    if np.linalg.norm(coords[idx] - last_target_coord) < 0.5:
                        if sc >= scored[0][0] * 0.75:
                            target_idx = idx
                        break
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            last_target_coord = coords[target_idx].copy()
        else:
            last_target_coord = None
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            else:
                chosen = neighbors[0]

        try:
            obs, info = env.step(chosen)
        except Exception as e:
            break
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=False, default=None)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    cfg_path = os.path.join(args.data_path, 'eval_config.json')
    with open(cfg_path, 'r') as f:
        cfg = json.load(f)

    if isinstance(cfg, dict):
        episodes = cfg.get('episodes', cfg.get('maps', []))
    elif isinstance(cfg, list):
        episodes = cfg
    else:
        episodes = []

    per_episode = []
    per_type = {}

    for ep in episodes:
        if isinstance(ep, str):
            map_rel = ep
            env_type = ep.split('/')[0] if '/' in ep else 'unknown'
        else:
            map_rel = ep.get('map_path') or ep.get('map') or ep.get('path')
            env_type = ep.get('env_type') or (map_rel.split('/')[0] if map_rel and '/' in map_rel else 'unknown')

        map_full = os.path.join(args.data_path, 'maps_eval', map_rel)
        if not os.path.exists(map_full):
            map_full = os.path.join(args.data_path, map_rel)

        try:
            m = plan_episode(map_full)
            success = 1 if m.get('explored_rate', 0) > 0.9999 else 0
            entry = {
                'map_path': map_rel,
                'env_type': env_type,
                'success': success,
                'travel_distance': float(m.get('travel_distance', 0.0)),
                'explored_rate': float(m.get('explored_rate', 0.0)),
            }
        except Exception as e:
            entry = {
                'map_path': map_rel,
                'env_type': env_type,
                'success': 0,
                'travel_distance': 0.0,
                'explored_rate': 0.0,
                'error': str(e),
            }
        per_episode.append(entry)
        per_type.setdefault(env_type, []).append(entry)

    if per_episode:
        explored_rate = float(np.mean([e['explored_rate'] for e in per_episode]))
        succ = [e for e in per_episode if e['success'] == 1]
        travel_distance = float(np.mean([e['travel_distance'] for e in succ])) if succ else 0.0
        success_rate = float(np.mean([e['success'] for e in per_episode]))
    else:
        explored_rate = 0.0
        travel_distance = 0.0
        success_rate = 0.0

    pt_summary = {}
    for k, lst in per_type.items():
        if not lst:
            continue
        succ_l = [e for e in lst if e['success'] == 1]
        pt_summary[k] = {
            'explored_rate': float(np.mean([e['explored_rate'] for e in lst])),
            'travel_distance': float(np.mean([e['travel_distance'] for e in succ_l])) if succ_l else 0.0,
            'success_rate': float(np.mean([e['success'] for e in lst])),
        }

    out = {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': pt_summary,
        'total_episodes': len(per_episode),
    }

    with open(args.output, 'w') as f:
        json.dump(out, f)


if __name__ == '__main__':
    main()
